-- ============================================================
-- Mock Students Import Script
-- Generated: 2026-07-14
-- Prefix: SIM2026 (001-100)
-- IMPORTANT: Execute with a MySQL client that has write access
--   mysql -u <user> -p < import_mock_students.sql
-- ============================================================

USE spark_employment;

START TRANSACTION;

-- Replace only the SIM2026 dataset so this script is safe to run repeatedly
DELETE FROM auth_session WHERE account_id IN (
  SELECT id FROM platform_account WHERE username LIKE 'SIM2026%'
);
DELETE FROM platform_account WHERE username LIKE 'SIM2026%';
DELETE FROM student_skill WHERE student_id IN (
  SELECT id FROM student WHERE student_no LIKE 'SIM2026%'
);
DELETE FROM student_experience WHERE student_id IN (
  SELECT id FROM student WHERE student_no LIKE 'SIM2026%'
);
DELETE FROM job_preference WHERE student_id IN (
  SELECT id FROM student WHERE student_no LIKE 'SIM2026%'
);
DELETE FROM student WHERE student_no LIKE 'SIM2026%';
SELECT 'Existing SIM2026 dataset cleared; importing 100 students' AS import_status;

-- ============================================================
-- 1. Student records
-- ============================================================

-- ============================================================
-- 2. Platform accounts
-- ============================================================

-- ============================================================
-- 3. Student skills
-- ============================================================

-- ============================================================
-- 4. Student experiences
-- ============================================================

-- ============================================================
-- 5. Job preferences
-- ============================================================

-- ============================================================
-- Verification counts
-- ============================================================
SELECT 'Students' AS tbl, COUNT(*) AS cnt FROM student WHERE student_no LIKE 'SIM2026%'
UNION ALL SELECT 'Accounts', COUNT(*) FROM platform_account WHERE username LIKE 'SIM2026%'
UNION ALL SELECT 'Skills', COUNT(*) FROM student_skill WHERE student_id IN (SELECT id FROM student WHERE student_no LIKE 'SIM2026%')
UNION ALL SELECT 'Experiences', COUNT(*) FROM student_experience WHERE student_id IN (SELECT id FROM student WHERE student_no LIKE 'SIM2026%')
UNION ALL SELECT 'Preferences', COUNT(*) FROM job_preference WHERE student_id IN (SELECT id FROM student WHERE student_no LIKE 'SIM2026%');

COMMIT;

-- End of import script